struct Trade: Identifiable, Codable {
    let id: UUID
    let stockSymbol: String
    let stockName: String
    let type: TradeType
    let quantity: Int
    let price: Double
    let timestamp: Date

    enum TradeType: String, Codable {
        case buy = "Buy"
        case sell = "Sell"
    }

    static var mock: Trade {
        Trade(id: UUID(), stockSymbol: "AAPL", stockName: "Apple Inc.", type: .buy, quantity: 10, price: 169.50, timestamp: Date().addingTimeInterval(-3600))
    }
}

struct PortfolioHolding: Identifiable, Codable {
    let id: String // Stock Symbol
    let stockName: String
    var quantity: Int
    var averagePrice: Double
    var currentValue: Double {
        quantity > 0 ? Double(quantity) * (APIService.shared.currentStockPrices[id] ?? averagePrice) : 0.0
    }
    var totalCost: Double {
        Double(quantity) * averagePrice
    }
    var profitLoss: Double {
        currentValue - totalCost
    }
    var profitLossPercentage: Double {
        totalCost > 0 ? (profitLoss / totalCost) * 100 : 0.0
    }
}

struct Portfolio: Codable {
    var holdings: [String: PortfolioHolding] // Key: Stock Symbol
    var cashBalance: Double
    var totalValue: Double {
        holdings.values.reduce(0) { $0 + $1.currentValue } + cashBalance
    }

    static var empty: Portfolio {
        Portfolio(holdings: [:], cashBalance: 10000.00)
    }
}

// MARK: - API Service (Mock)

enum APIError: Error, LocalizedError {
    case invalidURL
    case networkError(Error)
    case decodingError(Error)
    case serverError(statusCode: Int, message: String?)
    case tradeExecutionFailed(message: String?)
    case unknown

    var errorDescription: String? {
        switch self {
        case .invalidURL: return "Invalid API URL."
        case .networkError(let error): return "Network error: \(error.localizedDescription)"
        case .decodingError(let error): return "Data decoding error: \(error.localizedDescription)"
        case .serverError(let statusCode, let message): return "Server error \(statusCode): \(message ?? "Unknown")"
        case .tradeExecutionFailed(let message): return "Trade execution failed: \(message ?? "Unknown reason")"
        case .unknown: return "An unknown error occurred."
        }
    }
}

class APIService {
