        // Initialize with some mock holdings if empty
        if mockPortfolio.holdings.isEmpty {
            mockPortfolio.holdings["AAPL"] = PortfolioHolding(id: "AAPL", stockName: "Apple Inc.", quantity: 5, averagePrice: 165.00)
