    private func updateMockPrices() {
        for symbol in currentStockPrices.keys {
            let current = currentStockPrices[symbol] ?? 0
            let change = Double.random(in: -2.0...2.0)
            let newPrice = max(1.0, current + change) // Ensure price doesn't go below 1
            currentStockPrices[symbol] = newPrice
        }
