    func fetchMarketData() -> AnyPublisher<[Stock], APIError> {
        Future<[Stock], APIError> { promise in
            DispatchQueue.main.asyncAfter(deadline: .now() + self.mockLatency) {
                let stocks: [Stock] = self.currentStockPrices.map { (symbol, price) in
                    let previousPrice = price * (1 + Double.random(in: -0.01...0.01)) // Simulate a previous price
                    let priceChange = price - previousPrice
                    let percentageChange = (priceChange / previousPrice) * 100
                    return Stock(id: symbol, name: self.stockName(for: symbol), currentPrice: price, priceChange: priceChange, percentageChange: percentageChange)
                }
                promise(.success(stocks.sorted { $0.id < $1.id }))
            }
        }
        .eraseToAnyPublisher()
    }

    func fetchPortfolio() -> AnyPublisher<Portfolio, APIError> {
        Future<Portfolio, APIError> { promise in
            DispatchQueue.main.asyncAfter(deadline: .now() + self.mockLatency) {
                // Update current values in holdings based on latest prices
                var updatedHoldings = self.mockPortfolio.holdings
                for (symbol, holding) in updatedHoldings {
                    if let currentPrice = self.currentStockPrices[symbol] {
                        updatedHoldings[symbol]?.averagePrice = holding.averagePrice // Keep average price
                        // current value is a computed property, no need to set here
                    }
                }
                self.mockPortfolio.holdings = updatedHoldings
                promise(.success(self.mockPortfolio))
            }
        }
        .eraseToAnyPublisher()
    }

    func executeTrade(stockSymbol: String, type: Trade.TradeType, quantity: Int) -> AnyPublisher<Trade, APIError> {
        Future<Trade, APIError> { promise in
            DispatchQueue.main.asyncAfter(deadline: .now() + self.mockLatency) {
                guard let currentPrice = self.currentStockPrices[stockSymbol] else {
                    promise(.failure(.tradeExecutionFailed(message: "Stock not found or price unavailable.")))
                    return
                }

                let tradeCost = Double(quantity) * currentPrice
                var currentPortfolio = self.mockPortfolio

                switch type {
                case .buy:
                    guard currentPortfolio.cashBalance >= tradeCost else {
                        promise(.failure(.tradeExecutionFailed(message: "Insufficient cash balance.")))
                        return
                    }
                    currentPortfolio.cashBalance -= tradeCost

                    if var holding = currentPortfolio.holdings[stockSymbol] {
                        let newTotalCost = (holding.averagePrice * Double(holding.quantity)) + tradeCost
                        holding.quantity += quantity
                        holding.averagePrice = newTotalCost / Double(holding.quantity)
                        currentPortfolio.holdings[stockSymbol] = holding
                    } else {
                        currentPortfolio.holdings[stockSymbol] = PortfolioHolding(id: stockSymbol, stockName: self.stockName(for: stockSymbol), quantity: quantity, averagePrice: currentPrice)
                    }

                case .sell:
                    guard var holding = currentPortfolio.holdings[stockSymbol], holding.quantity >= quantity else {
                        promise(.failure(.tradeExecutionFailed(message: "Insufficient shares to sell.")))
                        return
                    }
                    currentPortfolio.cashBalance += tradeCost
                    holding.quantity -= quantity
                    if holding.quantity == 0 {
                        currentPortfolio.holdings.removeValue(forKey: stockSymbol)
                    } else {
                        currentPortfolio.holdings[stockSymbol] = holding
                    }
                }

                self.mockPortfolio = currentPortfolio
                let newTrade = Trade(id: UUID(), stockSymbol: stockSymbol, stockName: self.stockName(for: stockSymbol), type: type, quantity: quantity, price: currentPrice, timestamp: Date())
                self.mockTrades.insert(newTrade, at: 0) // Add to recent trades
                promise(.success(newTrade))
            }
        }
        .eraseToAnyPublisher()
    }

    func fetchTradeHistory() -> AnyPublisher<[Trade], APIError> {
        Future<[Trade], APIError> { promise in
            DispatchQueue.main.asyncAfter(deadline: .now() + self.mockLatency) {
                promise(.success(self.mockTrades))
            }
        }
        .eraseToAnyPublisher()
    }

    private func stockName(for symbol: String) -> String {
        switch symbol {
        case "AAPL": return "Apple Inc."
        case "GOOG": return "Alphabet Inc. (GOOG)"
        case "MSFT": return "Microsoft Corp."
        case "AMZN": return "Amazon.com Inc."
        case "TSLA": return "Tesla Inc."
        case "NVDA": return "NVIDIA Corp."
        default: return symbol
        }
    }
}

